// Loop sur companies — pour chaque, on génère un payload Apollo search
const max = $('Extract params').item.json.max_per_company;
const titles = [
  'CMO','Chief Marketing Officer','Directeur Marketing',
  'Head of Marketing','VP Marketing','Director of Marketing',
  'Head of Brand','Brand Director',
  'Head of Digital Marketing','Head of Digital',
  'Director of Communications','Head of Communications','Directeur Communication',
  'Head of Product Marketing','Director of Product Marketing'
];
const out = [];
for (const c of items) {
  out.push({ json: {
    company_id: c.json.company_id,
    company_name: c.json.nom,
    company_domain: c.json.domain,
    company_country: c.json.country,
    visibility_score: c.json.visibility_score,
    report_id: c.json.report_id,
    category_id: c.json.category_id,
    apollo_payload: {
      q_organization_domains: [c.json.domain],
      person_titles: titles,
      person_seniorities: ['c_suite','vp','director','head'],
      person_departments: ['marketing','c_suite'],
      page: 1,
      per_page: max * 4
    }
  } });
}
return out;

// Filter + map Apollo results to prospects rows
const src = $('Split per company').item.json;
const people = (items[0].json.people || items[0].json.contacts || []);
const max = $('Extract params').item.json.max_per_company;

// Scoring
function scoreLead(p, visibilityScore) {
  let s = 0;
  if (p.email_status === 'verified' || p.email_verified) s += 30;
  if (p.linkedin_url) s += 15;
  const t = (p.title || '').toLowerCase();
  if (/(cmo|chief marketing officer)/.test(t)) s += 25;
  else if (/(head of brand|head of digital)/.test(t)) s += 15;
  else if (/(vp marketing|director of marketing|directeur marketing)/.test(t)) s += 10;
  if (visibilityScore === 4) s += 15;
  else if (visibilityScore === 3) s += 10;
  else if (visibilityScore === 2) s += 5;
  return s;
}

const rows = people
  .filter(p => p.first_name && p.last_name)
  .map(p => {
    const score = scoreLead(p, src.visibility_score);
    return {
      company_id: src.company_id,
      category_id: src.category_id,
      report_id: src.report_id,
      apollo_person_id: p.id,
      first_name: p.first_name,
      last_name: p.last_name,
      full_name: p.name || `${p.first_name} ${p.last_name}`,
      email: p.email,
      email_verified: p.email_status === 'verified' || !!p.email_verified,
      phone: p.phone_numbers?.[0]?.sanitized_number || null,
      linkedin_url: p.linkedin_url,
      title: p.title,
      seniority: p.seniority,
      job_function: p.departments?.[0] || null,
      lead_score: score,
      metadata: {
        apollo_org_id: p.organization?.id,
        apollo_org_website: p.organization?.website_url,
        company_country: src.company_country,
        company_visibility_score: src.visibility_score
      }
    };
  })
  .sort((a, b) => b.lead_score - a.lead_score)
  .slice(0, max);

return rows.map(r => ({ json: r }));

// Toujours retourner au moins 1 item pour que splitInBatches sache qu'il doit continuer.
// Sinon : si Apollo retourne 0 (cas plan free), Score & filter renvoie [], Upsert et Log ne s'executent pas, et le loop s'arrete prematurement.
return [{ json: { __continue: true, processed_at: new Date().toISOString() } }];
